import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import { LayoutDashboard, Users, Clock, AlertCircle, Plus } from 'lucide-react';
import { fetchTasks } from '../api';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const token = localStorage.getItem('token');
  const userName = localStorage.getItem('name') || 'Guest';
  const userRole = localStorage.getItem('role') || 'member';

  const getTasks = async () => {
    try {
      const { data } = await fetchTasks();
      setTasks(data);
    } catch (err) { console.log(err); }
  };

  useEffect(() => { if(token) getTasks(); }, [token]);

  const getOverdue = () => tasks.filter(t => new Date(t.dueDate) < new Date() && t.status !== 'Completed').length;

  return (
    <div className="min-h-screen bg-[#0f172a] text-white">
      <Navbar />
      <AddTaskModal isOpen={isTaskModalOpen} onClose={() => setIsTaskModalOpen(false)} refreshTasks={getTasks} />

      <main className="pt-32 pb-12 px-6 max-w-7xl mx-auto">
        <header className="mb-12">
          <h1 className="text-5xl font-black tracking-tight">Hi, {userName} 👋</h1>
          <p className="text-gray-400 mt-3 text-lg">You are logged in as <span className="text-indigo-400 font-bold uppercase">{userRole}</span></p>
        </header>

        {/* Dynamic Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          {[
            { label: 'Total Tasks', val: tasks.length, color: 'text-blue-400', icon: <LayoutDashboard/> },
            { label: 'Overdue', val: getOverdue(), color: 'text-red-500', icon: <AlertCircle/> },
            { label: 'In Progress', val: tasks.filter(t => t.status === 'In Progress').length, color: 'text-yellow-400', icon: <Clock/> },
            { label: 'Team Members', val: userRole === 'admin' ? 'Active' : 'Connected', color: 'text-purple-400', icon: <Users/> },
          ].map((stat, i) => (
            <div key={i} className="p-6 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-md hover:bg-white/10 transition-all">
              <div className={`${stat.color} mb-3`}>{stat.icon}</div>
              <div className="text-3xl font-black">{stat.val}</div>
              <div className="text-gray-500 text-xs font-bold uppercase tracking-widest">{stat.label}</div>
            </div>
          ))}
        </div>

        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold">Project Board</h2>
          {userRole === 'admin' && (
            <button onClick={() => setIsTaskModalOpen(true)} className="bg-indigo-600 px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-indigo-500 transition-all">
              <Plus size={20}/> New Project Task
            </button>
          )}
        </div>

        {/* Task Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {tasks.length > 0 ? tasks.map(t => (
            <TaskCard key={t._id} task={t} refreshTasks={getTasks} />
          )) : (
            <div className="col-span-full py-20 text-center border-2 border-dashed border-white/10 rounded-3xl text-gray-500">
              No assignments found for your profile.
            </div>
          )}
        </div>
      </main>

      <Footer />
    </div>
  );
};

export default Dashboard;
